import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import eventApi from "../../api/eventApi";

export default function AddEvent() {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [formData, setFormData] = useState({
    name: "",
    type: "holiday",
    description: "",
    startDate: "",
    endDate: "",
    isShopClosed: true,
    color: "#4CAF50"
  });

  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: type === "checkbox" ? checked : value
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError(null);

    // Validation
    if (!formData.name.trim()) {
      setError("Event name is required");
      return;
    }
    if (!formData.startDate) {
      setError("Start date is required");
      return;
    }
    if (!formData.endDate) {
      setError("End date is required");
      return;
    }
    if (new Date(formData.endDate) < new Date(formData.startDate)) {
      setError("End date must be on or after start date");
      return;
    }

    try {
      setLoading(true);
      await eventApi.createEvent(formData);
      navigate("/events");
    } catch (err) {
      console.error("Event creation error:", err);
      const errorMsg = err.response?.data?.error || err.response?.data?.message || err.message || "Failed to create event";
      const details = err.response?.data?.details;
      setError(details ? `${errorMsg}: ${details.join(", ")}` : errorMsg);
    } finally {
      setLoading(false);
    }
  };

  const colors = ["#4CAF50", "#ff9800", "#f44336", "#2196f3", "#9c27b0", "#00bcd4"];
  const types = [
    { value: "holiday", label: "Holiday" },
    { value: "weather", label: "Weather Issue" },
    { value: "flood", label: "Flood/Disaster" },
    { value: "special", label: "Special Closure" },
    { value: "other", label: "Other" }
  ];

  return (
    <div className="page">
      <div className="pageHead">
        <div className="pageHeadLeft">
          <h1 className="h1">Add New Event</h1>
          <p className="pageSub">Create a new shop closure or special event</p>
        </div>
      </div>

      <div className="card" style={{ maxWidth: "600px", margin: "0 auto" }}>
        {error && (
          <div style={{
            padding: "16px",
            backgroundColor: "#ffebee",
            color: "#c62828",
            borderRadius: "10px",
            marginBottom: "24px",
            fontSize: "14px"
          }}>
            {error}
          </div>
        )}

        <form onSubmit={handleSubmit} style={{ display: "flex", flexDirection: "column", gap: "24px" }}>
          {/* Event Name */}
          <div>
            <label className="label">Event Name *</label>
            <input
              type="text"
              name="name"
              value={formData.name}
              onChange={handleChange}
              placeholder="e.g., New Year Holiday, Monsoon Closure"
              className="input"
            />
          </div>

          {/* Event Type */}
          <div>
            <label className="label">Event Type *</label>
            <select
              name="type"
              value={formData.type}
              onChange={handleChange}
              className="select"
            >
              {types.map(t => (
                <option key={t.value} value={t.value}>{t.label}</option>
              ))}
            </select>
          </div>

          {/* Date Range */}
          <div style={{
            display: "grid",
            gridTemplateColumns: "1fr 1fr",
            gap: "16px"
          }}>
            <div>
              <label className="label">Start Date *</label>
              <input
                type="date"
                name="startDate"
                value={formData.startDate}
                onChange={handleChange}
                className="input"
              />
            </div>
            <div>
              <label className="label">End Date *</label>
              <input
                type="date"
                name="endDate"
                value={formData.endDate}
                onChange={handleChange}
                className="input"
              />
            </div>
          </div>

          {/* Description */}
          <div>
            <label className="label">Description</label>
            <textarea
              name="description"
              value={formData.description}
              onChange={handleChange}
              placeholder="Add details about this event..."
              className="textarea"
              style={{ minHeight: "120px" }}
            />
          </div>

          {/* Shop Closed Toggle */}
          <div style={{
            padding: "16px",
            backgroundColor: "var(--bg-hover)",
            borderRadius: "10px",
            display: "flex",
            alignItems: "center",
            gap: "12px"
          }}>
            <input
              type="checkbox"
              name="isShopClosed"
              id="shopClosed"
              checked={formData.isShopClosed}
              onChange={handleChange}
              style={{ width: "18px", height: "18px", cursor: "pointer" }}
            />
            <label htmlFor="shopClosed" style={{ cursor: "pointer", flex: 1, margin: 0 }}>
              <strong>Shop is Closed</strong>
              <div style={{ fontSize: "13px", color: "var(--text-muted)", marginTop: "4px" }}>
                Customers cannot book appointments on these days
              </div>
            </label>
          </div>

          {/* Color Picker */}
          <div>
            <label className="label">Event Color</label>
            <div style={{
              display: "flex",
              gap: "12px",
              flexWrap: "wrap"
            }}>
              {colors.map(color => (
                <button
                  key={color}
                  type="button"
                  onClick={() => setFormData(prev => ({ ...prev, color }))}
                  style={{
                    width: "48px",
                    height: "48px",
                    backgroundColor: color,
                    border: formData.color === color ? "3px solid var(--primary)" : "2px solid var(--border)",
                    borderRadius: "10px",
                    cursor: "pointer",
                    transition: "all 0.2s ease",
                    boxShadow: formData.color === color ? "0 4px 12px rgba(76, 175, 80, 0.3)" : "none"
                  }}
                />
              ))}
            </div>
          </div>

          {/* Actions */}
          <div style={{
            display: "flex",
            gap: "12px",
            paddingTop: "24px",
            borderTop: "1px solid var(--border)"
          }}>
            <button
              type="button"
              className="btn"
              onClick={() => navigate("/events")}
              disabled={loading}
              style={{ flex: 1 }}
            >
              Cancel
            </button>
            <button
              type="submit"
              className="btn btnPrimary"
              disabled={loading}
              style={{ flex: 1 }}
            >
              {loading ? "Creating..." : "Create Event"}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
